package hw05.model.updateStrategies;

import hw05.model.IBall;
import hw05.model.IBallCmd;
import provided.utils.dispatcher.IDispatcher;

/**
 * The Criteria strategy that is satisfied when the two balls collide
 * @author cindy
 *
 */
public class CollideCriteriaStrategy implements IUpdateStrategy{

	@Override
	public void updateState(final IBall source, IDispatcher<IBallCmd> dispatcher) {
		dispatcher.updateAll(new IBallCmd() {
			@Override
			public void apply(IBall target, IDispatcher<IBallCmd> disp) {
				if (target == source) return;
				double dx = target.getLocation().x - source.getLocation().x;
				double dy = target.getLocation().y - source.getLocation().y;
				double distance = Math.sqrt(dx * dx + dy * dy);
				double minSep = source.getRadius() + target.getRadius();
				if (distance < minSep) {
					IBallCmd cmd = source.interactWithThen(target, disp);
					cmd.apply(source, disp);
				}
			}
		});
	}

	@Override
	public void init(IBall context) {
		// no-op
	}

}

package hw05.model.interactStrategies;

import hw05.model.IBall;
import hw05.model.IBallCmd;
import provided.utils.dispatcher.IDispatcher;

/**
 * If the criteria is met, the balls will be set to have the same inherent traits (radius and color)
 * Unlike the infect strategy, the ball that passes its traits is arbitrary, so you get to see an
 * evolution of sorts within the population, like if smaller balls or larger balls are more likely to
 * pass traits based on average number of interactions.
 * @author charlielockyer
 *
 */
public class CloneTraitsStrategy implements IInteractStrategy{

	public IBallCmd interactWith(IBall context, IBall target, IDispatcher<IBallCmd> disp) {
		final IBall capturedTarget = target;
		return (ball, d) -> {
			ball.setRadius(capturedTarget.getRadius());
			ball.setColor(capturedTarget.getColor());
		};
	}

	@Override
	public void init(IBall context) {
		// TODO Auto-generated method stub

	}

}

